class Playground {
  async run(inputs) {
    const nums = inputs[0].split(',').map(x => parseInt(x.trim()));
    this.array.init(nums);
    this.log('Find Maximum and Minimum in array');
    await this.await();

    let max = nums[0];
    let min = nums[0];
    let maxIdx = 0;
    let minIdx = 0;

    this.array.highlight(0, '#f59e0b');
    this.log(`Start: max=${max}, min=${min}`);
    await this.await();

    for (let i = 1; i < nums.length; i++) {
      this.ptr.set('i', i);
      this.array.highlight(i, '#3b82f6');
      this.log(`Checking index ${i}: value = ${nums[i]}`);
      await this.await();

      if (nums[i] > max) {
        this.array.highlight(maxIdx, '#64748b');
        max = nums[i];
        maxIdx = i;
        this.array.highlight(i, '#10b981');
        this.log(`🔺 New max found: ${max}`);
        await this.await();
      } else if (nums[i] < min) {
        this.array.highlight(minIdx, '#64748b');
        min = nums[i];
        minIdx = i;
        this.array.highlight(i, '#ef4444');
        this.log(`🔻 New min found: ${min}`);
        await this.await();
      } else {
        this.log(`${nums[i]} is between min and max`);
        this.array.highlight(i, '#64748b');
        await this.await();
      }
    }

    this.ptr.remove('i');
    this.array.clearHighlights();
    this.array.highlight(maxIdx, '#10b981');
    this.array.highlight(minIdx, '#ef4444');
    this.log(`✅ Result: Max = ${max} at index ${maxIdx}, Min = ${min} at index ${minIdx}`);
    await this.await();

    return { max, min };
  }
}
